const j = $input.first();
if (!j) return [];

const url         = j.json.jobUrl || j.json.url || j.json.link || '';
const title       = j.json.title || j.json.jobTitle || j.json.position || '';
const company     = j.json.company || j.json.companyName || '';
const location    = j.json.location || j.json.jobLocation || '';
const description = j.json.description || j.json.jobDescription || j.json.descriptionHtml || '';

if (!url || !title || !description || description.length < 100) return [];

return [{ json: { url, title, company, location, description } }];

