// Parse LLM response; keep only confirmed relocation jobs.
// includeInputData: true merges input fields into $json alongside the LLM response.
const items = $input.all();
const results = [];

for (const item of items) {
  if (!item?.json) continue;
  try {
    const raw     = item.json?.choices?.[0]?.message?.content || '';
    const cleaned = raw.replace(/```json|```/g, '').trim();
    const parsed  = JSON.parse(cleaned);

    if (!parsed.offers_relocation)      continue;
    if (parsed.confidence === 'low')    continue;

    results.push({
      json: {
        url:                   item.json.url         || '',
        title:                 item.json.title        || '',
        company:               item.json.company      || '',
        location:              item.json.location     || '',
        description:           item.json.description  || '',
        relocation_signals:    (parsed.signals || []).join(', '),
        relocation_confidence: parsed.confidence
      }
    });
  } catch (e) { continue; }
}

return results;

